        while (left < right) {
            if (s[left] !== s[right]) return false;
            left++;
            right--;
        }
        return true;
    }

    // DFS to explore all paths
    function dfs(node: number, path: number[], visited: number, currentLabel: string): void {
        // Check if current path forms a palindrome
